-- Clean up stale/fake feed items
DELETE FROM feed_items WHERE metadata->>'demo' = 'true';
DELETE FROM feed_items WHERE metadata->>'demo_batch' IS NOT NULL;
DELETE FROM feed_items WHERE feed_type = 'milestone' AND (title ILIKE '%complete%assessment%' OR title ILIKE '%completa%valutazione%') AND user_id IN (SELECT user_id FROM profiles WHERE pillar_scores IS NOT NULL);
DELETE FROM feed_items WHERE body IS NULL OR body = '';
DELETE FROM feed_items WHERE created_at < now() - interval '90 days';

-- Seed external content
ON CONFLICT DO NOTHING;